4641: static int ata_dma_blacklisted(const struct ata_device *dev)
4642: {
4643: 	/* We don't support polling DMA.
4644: 	 * DMA blacklist those ATAPI devices with CDB-intr (and use PIO)
4645: 	 * if the LLDD handles only interrupts in the HSM_ST_LAST state.
4646: 	 */
4647: 	if ((dev->link->ap->flags & ATA_FLAG_PIO_POLLING) &&
4648: 	    (dev->flags & ATA_DFLAG_CDB_INTR))
